import {SelectButton as SelectButtonPrime, type SelectButtonProps} from "primereact/selectbutton";
import { useKitsTheme } from "../../../contexts/Theme";

export const SelectButton = (props:SelectButtonProps)=>{
    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');

    return <SelectButtonPrime
        {...props}
        pt={{
            button: ({ context }: any) => context?.selected ? {
                style: { backgroundColor: primaryColor, color: 'white', borderColor: primaryColor }
            } : undefined,
            ...props.pt,
        }}
    />
}
